# Do-While (executes at least once)
$num = 0
do {
    Write-Host "Num: $num"
    $num++
} while ($num -lt 3)

# Do-Until
$x = 10
do {
    Write-Host $x
    $x--
} until ($x -eq 0)

# Break exits the loop
for ($i = 0; $i -lt 10; $i++) {
    if ($i -eq 5) { break }
    Write-Host $i
}

# Continue skips to next iteration
for ($i = 0; $i -lt 10; $i++) {
    if ($i % 2 -eq 0) { continue }
    Write-Host "Odd: $i"
}

# Labeled break for nested loops
:outer for ($i = 0; $i -lt 3; $i++) {
    for ($j = 0; $j -lt 3; $j++) {
        if ($j -eq 1) { break outer }
        Write-Host "$i,$j"
    }
}

