function Get-UserInfo {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory=$true, ValueFromPipeline=$true)]
        [string]$Username,

        [Parameter()]
        [ValidateSet('Basic', 'Detailed', 'Full')]
        [string]$Level = 'Basic',

        [Parameter()]
        [ValidateRange(1, 100)]
        [int]$MaxResults = 10,

        [switch]$IncludeGroups
    )

    begin {
        Write-Verbose 'Starting user info retrieval...'
        $results = @()
    }

    process {
        Write-Verbose "Processing: $Username"
        $user = [PSCustomObject]@{
            Username = $Username
            Level    = $Level
            Groups   = if ($IncludeGroups) { @('Admins','Users') } else { @() }
        }
        $results += $user
    }

    end {
        Write-Verbose 'Done.'
        return $results | Select-Object -First $MaxResults
    }
}

# Usage
