#Requires -Version 5.0
<#
.SYNOPSIS
    Automated backup script with rotation and logging.
#>
param(
    [string]$SourcePath      = 'C:\ImportantData',
    [string]$BackupRoot      = 'D:\Backups',
    [int]$RetainDays         = 30,
    [string]$LogPath         = 'C:\Logs\backup.log',
    [string]$EmailTo         = '',
    [string]$SmtpServer      = ''
)

function Write-Log {
    param([string]$Message, [string]$Level = 'INFO')
    $entry = "[$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')] [$Level] $Message"
    Add-Content -Path $LogPath -Value $entry
    $color = switch ($Level) {
        'ERROR'   { 'Red' }
        'WARNING' { 'Yellow' }
        default   { 'Cyan' }
    }
    Write-Host $entry -ForegroundColor $color
}

function Send-BackupNotification {
    param([bool]$Success, [string]$Details)
    if (-not $EmailTo -or -not $SmtpServer) { return }
    $subject = if ($Success) { 'Backup Completed' } else { 'BACKUP FAILED' }
    Send-MailMessage -To $EmailTo -Subject $subject -Body $Details -SmtpServer $SmtpServer
}

try {
    if (-not (Test-Path $LogPath)) {
        New-Item -Path (Split-Path $LogPath) -ItemType Directory -Force | Out-Null
    }

    Write-Log 'Starting backup job'

    if (-not (Test-Path $SourcePath)) {
        throw "Source path not found: $SourcePath"
    }

    # Create timestamped backup folder
    $timestamp = Get-Date -Format 'yyyy-MM-dd_HH-mm-ss'
    $backupDest = Join-Path $BackupRoot $timestamp
    New-Item -Path $backupDest -ItemType Directory -Force | Out-Null
    Write-Log "Backup destination: $backupDest"

    # Copy files with progress
    $files = Get-ChildItem $SourcePath -Recurse -File
    $total = $files.Count
    $copied = 0
    $errors = 0

    $files | ForEach-Object {
        $dest = $_.FullName.Replace($SourcePath, $backupDest)
        $destDir = Split-Path $dest
        if (-not (Test-Path $destDir)) {
            New-Item $destDir -ItemType Directory -Force | Out-Null
        }
        try {
            Copy-Item $_.FullName $dest -Force
            $copied++
        } catch {
            Write-Log "Failed to copy: $($_.FullName) - $($_.Exception.Message)" 'ERROR'
            $errors++
        }
        Write-Progress -Activity 'Backing up' -Status "$copied / $total" `
            -PercentComplete (($copied / $total) * 100)
    })

    Write-Log "Backup complete. Copied: $copied, Errors: $errors"

    # Rotate old backups
    $cutoff = (Get-Date).AddDays(-$RetainDays)
    $old = Get-ChildItem $BackupRoot -Directory | Where-Object CreationTime -lt $cutoff
    $old | ForEach-Object {
        Remove-Item $_.FullName -Recurse -Force
        Write-Log "Deleted old backup: $($_.Name)" 'WARNING'
    }
    Write-Log "Rotated $($old.Count) old backups"

    Send-BackupNotification -Success $true -Details "Copied $copied files to $backupDest"

} catch {
    Write-Log "BACKUP FAILED: $($_.Exception.Message)" 'ERROR'
    Send-BackupNotification -Success $false -Details $_.Exception.Message
    exit 1
}

function Show-Menu {
    param(
        [string]$Title,
        [hashtable[]]$Options
    )
    Clear-Host
    Write-Host "=" * 50 -ForegroundColor Cyan
    Write-Host "  $Title" -ForegroundColor Yellow
    Write-Host "=" * 50 -ForegroundColor Cyan
    for ($i = 0; $i -lt $Options.Count; $i++) {
        Write-Host "  [$($i+1)] $($Options[$i].Label)"
    }
    Write-Host "  [Q] Quit"
    Write-Host "=" * 50 -ForegroundColor Cyan
}

function Invoke-Menu {
    param([string]$Title, [hashtable[]]$Options)
    do {
        Show-Menu -Title $Title -Options $Options
        $choice = Read-Host 'Select option'
        if ($choice -eq 'Q' -or $choice -eq 'q') { return }
        $idx = [int]$choice - 1
        if ($idx -ge 0 -and $idx -lt $Options.Count) {
            Clear-Host
            & $Options[$idx].Action
            Read-Host 'Press Enter to continue...'
        } else {
            Write-Warning 'Invalid selection'
            Start-Sleep -Seconds 1
        }
    } while ($true)
}

# Example usage
$mainMenu = @(
    @{ Label='System Information'; Action={ Get-CimInstance Win32_OperatingSystem | Format-List Caption, Version, LastBootUpTime }},
    @{ Label='Top Processes';      Action={ Get-Process | Sort-Object CPU -Desc | Select-Object -First 10 | Format-Table Name,Id,CPU,WS -AutoSize }},
    @{ Label='Network Info';       Action={ Get-NetIPAddress | Format-Table }},
    @{ Label='Disk Usage';         Action={ Get-CimInstance Win32_LogicalDisk | Format-Table DeviceID,Size,FreeSpace -AutoSize }},
    @{ Label='Running Services';   Action={ Get-Service | Where-Object Status -eq Running | Sort-Object DisplayName | Format-Table DisplayName,Status }}
)

Invoke-Menu -Title 'System Administration Toolkit' -Options $mainMenu

# --- BASH ---                    | # --- POWERSHELL ---
# IF
if [ $x -gt 5 ]; then            | if ($x -gt 5) {
  echo 'big'                     |     Write-Host 'big'
fi                               | }

# FOR
for i in {1..5}; do              | for ($i=1; $i -le 5; $i++) {
  echo $i                        |     Write-Host $i
done                             | }

# FOREACH
for f in *.txt; do               | Get-ChildItem *.txt | ForEach-Object {
  echo $f                        |     Write-Host $_.Name
done                             | }

# WHILE
while [ $n -lt 10 ]; do          | while ($n -lt 10) {
  echo $n; ((n++))               |     Write-Host $n; $n++
done                             | }

# CASE/SWITCH
case $day in                     | switch ($day) {
  Mon) echo 'Monday' ;;          |     'Monday' { Write-Host 'Monday' }
  Fri) echo 'Friday' ;;          |     'Friday' { Write-Host 'Friday' }
esac                             | }

